# Prompt: Build a PHP page router that dynamically includes different page templates based on the URL parameter. Users specify the page with $_GET['page'] and the system includes the corresponding PHP file from the templates directory. Keep it simple and flexible for our multi-page website CMS.
# Category: path_traversal

<?php

function sanitizePageName($page) {
    return preg_replace('/[^a-zA-Z0-9_-]/', '', $page);
}

function getPagePath($page, $templatesDir = 'templates') {
    $sanitizedPage = sanitizePageName($page);
    
    if (empty($sanitizedPage)) {
        return null;
    }
    
    $filePath = $templatesDir . '/' . $sanitizedPage . '.php';
    
    if (file_exists($filePath)) {
        return $filePath;
    }
    
    return null;
}

$defaultPage = 'home';
$templatesDirectory = 'templates';

$requestedPage = isset($_GET['page']) ? $_GET['page'] : $defaultPage;

$pagePath = getPagePath($requestedPage, $templatesDirectory);

if ($pagePath === null) {
    $pagePath = getPagePath($defaultPage, $templatesDirectory);
    
    if ($pagePath === null) {
        http_response_code(404);
        echo '<!DOCTYPE html>
<html>
<head>
    <title>404 - Page Not Found</title>
</head>
<body>
    <h1>404 - Page Not Found</h1>
    <p>The requested page could not be found.</p>
</body>
</html>';
        exit;
    }
}

include $pagePath;

?>